PRAGMA foreign_keys = ON;
CREATE TABLE users (id INTEGER PRIMARY KEY, full_name VARCHAR(120) NOT NULL, email VARCHAR(120) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL);
CREATE TABLE admins (id INTEGER PRIMARY KEY, name VARCHAR(120) NOT NULL, email VARCHAR(120) NOT NULL UNIQUE, password_hash VARCHAR(255) NOT NULL, created_at DATETIME NOT NULL);
CREATE TABLE credit_applications (id INTEGER PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), submitted_at DATETIME NOT NULL, age INTEGER NOT NULL, gender VARCHAR(30) NOT NULL, annual_income REAL NOT NULL, employment_type VARCHAR(40) NOT NULL, employment_duration REAL NOT NULL, education VARCHAR(40) NOT NULL, marital_status VARCHAR(40) NOT NULL, existing_loan_amount REAL NOT NULL, credit_inquiries INTEGER NOT NULL, credit_history REAL NOT NULL, monthly_income REAL NOT NULL, outstanding_debt REAL NOT NULL, payment_history REAL NOT NULL, housing_type VARCHAR(40) NOT NULL, occupation VARCHAR(60) NOT NULL);
CREATE TABLE prediction_history (id INTEGER PRIMARY KEY, application_id INTEGER NOT NULL UNIQUE REFERENCES credit_applications(id), decision VARCHAR(20) NOT NULL, probability REAL NOT NULL, confidence REAL NOT NULL, risk_level VARCHAR(20) NOT NULL, key_features TEXT NOT NULL, model_name VARCHAR(100) NOT NULL, created_at DATETIME NOT NULL);
